enum class ConfigKey(val label: String, val key: String) { MAX_TOKENS(label = "Max tokens", key = "maxTokens"), TOPK(label = "Top-K", key = "topK"), TOPP(label = "Top-P", key = "topP"), TEMPERATURE(label = "Temperature", key = "temperature"), ACCELERATOR(label = "Accelerator", key = "accelerator"), }
