import android.content.Context import android.util.Log import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.flow.Flow import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.withContext import androidx.work.Constraints import androidx.work.Data import androidx.work.NetworkType import androidx.work.OneTimeWorkRequestBuilder import androidx.work.WorkInfo import androidx.work.WorkManager import kotlinx.coroutines.flow.Flow import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.map import java.io.File import java.net.HttpURLConnection import java.net.URL
private const val TAG = "QwenDownloadRepository"
enum class DownloadStatus { NOT_DOWNLOADED, DOWNLOADING, DOWNLOADED, FAILED, }
data class DownloadState( val status: DownloadStatus = DownloadStatus.NOT_DOWNLOADED, val progress: Float = 0f, val errorMessage: String = "", )
import dagger.hilt.android.qualifiers.ApplicationContext import javax.inject.Inject import javax.inject.Singleton
@Singleton class DownloadRepository @Inject constructor(@ApplicationContext private val context: Context) { private val workManager = WorkManager.getInstance(context) private val _downloadStates = MutableStateFlow<Map<String, DownloadState>>(emptyMap())
fun getDownloadState(model: Model): DownloadState { return if (model.isDownloaded(context)) { DownloadState(status = DownloadStatus.DOWNLOADED) } else { _downloadStates.value[model.name] ?: DownloadState(status = DownloadStatus.NOT_DOWNLOADED) } }
fun observeWorkInfo(model: Model): Flow<DownloadState> { return workManager.getWorkInfosForUniqueWorkFlow(model.name) .map { infos -> val info = infos.firstOrNull() ?: return@map getDownloadState(model) val progress = info.progress.getInt("progress", 0) / 100f val state = when (info.state) { WorkInfo.State.ENQUEUED, WorkInfo.State.RUNNING -> DownloadState(status = DownloadStatus.DOWNLOADING, progress = progress) WorkInfo.State.SUCCEEDED -> DownloadState(status = DownloadStatus.DOWNLOADED, progress = 1f) WorkInfo.State.FAILED -> DownloadState(status = DownloadStatus.FAILED, errorMessage = info.outputData.getString("error") ?: "Download failed") else -> getDownloadState(model) } _downloadStates.value = _downloadStates.value.toMutableMap().also { it[model.name] = state } state } }
fun downloadModel(model: Model) { val constraints = Constraints.Builder() .setRequiredNetworkType(NetworkType.CONNECTED) .build()
val inputData = Data.Builder() .putString("modelName", model.name) .putString("modelUrl", model.url) .putString("targetPath", "${context.getExternalFilesDir(null)}/${model.normalizedName}/${model.version}") .putString("downloadFileName", model.downloadFileName) .putString("sha256", model.sha256) .build()
val downloadRequest = OneTimeWorkRequestBuilder<DownloadWorker>() .setConstraints(constraints) .setInputData(inputData) .addTag("download") .build()
workManager.enqueueUniqueWork( model.name, androidx.work.ExistingWorkPolicy.KEEP, downloadRequest ) }
fun deleteModel(model: Model): Boolean { return try { workManager.cancelUniqueWork(model.name) val dir = File("${context.getExternalFilesDir(null)}/${model.normalizedName}/${model.version}") dir.deleteRecursively() _downloadStates.value = _downloadStates.value.toMutableMap().also { it.remove(model.name) } true } catch (e: Exception) { Log.e(TAG, "Delete failed: ${e.message}") false } } }package com.qwen.vision.data
import android.content.Context import android.util.Log import androidx.work.CoroutineWorker import androidx.work.WorkerParameters import androidx.work.workDataOf import java.io.File import java.io.FileOutputStream import java.io.RandomAccessFile import java.net.HttpURLConnection import java.net.URL
private const val TAG = "DownloadWorker"
class DownloadWorker( appContext: Context, workerParams: WorkerParameters ) : CoroutineWorker(appContext, workerParams) {
override suspend fun doWork(): Result { val modelName = inputData.getString("modelName") ?: return Result.failure() val modelUrl = inputData.getString("modelUrl") ?: return Result.failure() val targetPath = inputData.getString("targetPath") ?: return Result.failure() val downloadFileName = inputData.getString("downloadFileName") ?: return Result.failure()
return try { downloadFile(modelName, modelUrl, targetPath, downloadFileName)
val expectedSha256 = inputData.getString("sha256") if (expectedSha256 != null) { val file = File(targetPath, downloadFileName) val actualSha256 = calculateSha256(file) if (actualSha256 != expectedSha256) { file.delete() throw Exception("Checksum verification failed for $modelName. Expected: $expectedSha256, Actual: $actualSha256") } Log.d(TAG, "Checksum verified for $modelName") }
Result.success() } catch (e: Exception) { Log.e(TAG, "Download failed for $modelName: ${e.message}") Result.failure(workDataOf("error" to (e.message ?: "Unknown error"))) } }
private fun calculateSha256(file: File): String { val digest = java.security.MessageDigest.getInstance("SHA-256") val buffer = ByteArray(8192) val fis = file.inputStream() var read: Int while (fis.read(buffer).also { read = it } != -1) { digest.update(buffer, 0, read) } fis.close() return digest.digest().joinToString("") { "%02x".format(it) } }
private fun downloadFile(modelName: String, urlString: String, targetPath: String, fileName: String) { val dir = File(targetPath) if (!dir.exists()) dir.mkdirs()
val outFile = File(dir, fileName) val existingLength = if (outFile.exists()) outFile.length() else 0L
val url = URL(urlString) val connection = url.openConnection() as HttpURLConnection
if (existingLength > 0) { Log.d(TAG, "Resuming download for $modelName from $existingLength bytes") connection.setRequestProperty("Range", "bytes=$existingLength-") }
connection.connect()
val responseCode = connection.responseCode if (responseCode != HttpURLConnection.HTTP_OK && responseCode != HttpURLConnection.HTTP_PARTIAL) { throw Exception("Server returned HTTP $responseCode") }
val totalSize = connection.contentLengthLong + existingLength val inputStream = connection.inputStream
val fileMode = if (existingLength > 0) "rw" else "rw" val raf = RandomAccessFile(outFile, "rw") raf.seek(existingLength)
val buffer = ByteArray(8192) var downloaded = existingLength var bytesRead: Int
while (inputStream.read(buffer).also { bytesRead = it } != -1) { if (isStopped) { raf.close() inputStream.close() return } raf.write(buffer, 0, bytesRead) downloaded += bytesRead
val progress = (downloaded.toFloat() / totalSize * 100).toInt() setProgressAsync(workDataOf("progress" to progress)) }
raf.close() inputStream.close() connection.disconnect() Log.d(TAG, "Download completed for $modelName") } }package com.qwen.vision.data
