data class ModelDataFile( val name: String, val url: String, val downloadFileName: String, val sizeInBytes: Long, val sha256: String? = null, )
enum class Accelerator(val label: String) { CPU(label = "CPU"), GPU(label = "GPU") }
const val IMPORTS_DIR = "__imports" private val NORMALIZE_NAME_REGEX = Regex("[^a-zA-Z0-9]")
/** A model for a task */ data class Model( val name: String, val version: String = "_", val downloadFileName: String, val url: String, val sizeInBytes: Long, val extraDataFiles: List<ModelDataFile> = listOf(), val info: String = "", val learnMoreUrl: String = "", val configs: List<Config> = listOf(), val showBenchmarkButton: Boolean = true, val isZip: Boolean = false, val unzipDir: String = "", val sha256: String? = null, /** Whether this model supports image input (multimodal). */ val llmSupportImage: Boolean = false, val imported: Boolean = false, var normalizedName: String = "", var instance: Any? = null, var configValues: MutableMap<ConfigKey, ConfigValue> = mutableMapOf(), ) { init { if (normalizedName.isEmpty()) { normalizedName = name.replace(NORMALIZE_NAME_REGEX, "_").lowercase() } }
fun getPath(context: Context): String { return if (imported) { downloadFileName } else { "${context.getExternalFilesDir(null)}/$normalizedName/$version/$downloadFileName" } }
fun isDownloaded(context: Context): Boolean { if (imported) return File(downloadFileName).exists() val file = File(getPath(context)) return file.exists() && file.length() > 0 }
fun getIntConfigValue(key: ConfigKey, defaultValue: Int): Int { return when (val v = configValues[key]) { is ConfigValue.IntValue -> v.value is ConfigValue.FloatValue -> v.value.toInt() else -> defaultValue } }
fun getFloatConfigValue(key: ConfigKey, defaultValue: Float): Float { return when (val v = configValues[key]) { is ConfigValue.FloatValue -> v.value is ConfigValue.IntValue -> v.value.toFloat() else -> defaultValue } }
fun getStringConfigValue(key: ConfigKey, defaultValue: String): String { return when (val v = configValues[key]) { is ConfigValue.StringValue -> v.value is ConfigValue.IntValue -> "${v.value}" is ConfigValue.FloatValue -> "${v.value}" else -> defaultValue } } }package com.qwen.vision.data
