private val QWEN_VISION_CONFIGS = listOf( LabelConfig(key = ConfigKey.MAX_TOKENS, defaultValue = "2048"), NumberSliderConfig(key = ConfigKey.TOPK, sliderMin = 1f, sliderMax = 100f, defaultValue = 40f, valueType = ValueType.INT), NumberSliderConfig(key = ConfigKey.TOPP, sliderMin = 0f, sliderMax = 1f, defaultValue = 0.95f, valueType = ValueType.FLOAT), NumberSliderConfig(key = ConfigKey.TEMPERATURE, sliderMin = 0f, sliderMax = 2f, defaultValue = 0.7f, valueType = ValueType.FLOAT), )
@Serializable data class AllowedModel( val name: String, val modelId: String, val modelFile: String, val description: String, val sizeInBytes: Long, val version: String, val defaultConfig: Map<String, Double> = emptyMap(), val taskTypes: List<String>, val llmSupportImage: Boolean = false, ) { fun toModel(): Model { val downloadUrl = "https://huggingface.co/$modelId/resolve/main/$modelFile?download=true"
val topK = defaultConfig["topK"]?.toInt() ?: 40 val topP = defaultConfig["topP"]?.toFloat() ?: 0.95f val temperature = defaultConfig["temperature"]?.toFloat() ?: 0.7f val maxTokens = defaultConfig["maxTokens"]?.toInt() ?: 2048 val acceleratorsStr = "gpu" // default
val acceleratorOptions = listOf(Accelerator.GPU.label, Accelerator.CPU.label) val configs = listOf( LabelConfig(key = ConfigKey.MAX_TOKENS, defaultValue = "$maxTokens"), NumberSliderConfig(key = ConfigKey.TOPK, sliderMin = 1f, sliderMax = 100f, defaultValue = topK.toFloat(), valueType = ValueType.INT), NumberSliderConfig(key = ConfigKey.TOPP, sliderMin = 0f, sliderMax = 1f, defaultValue = topP, valueType = ValueType.FLOAT), NumberSliderConfig(key = ConfigKey.TEMPERATURE, sliderMin = 0f, sliderMax = 2f, defaultValue = temperature, valueType = ValueType.FLOAT), SegmentedButtonConfig(key = ConfigKey.ACCELERATOR, defaultValue = Accelerator.GPU.label, options = acceleratorOptions), )
val configValues: MutableMap<ConfigKey, ConfigValue> = mutableMapOf( ConfigKey.MAX_TOKENS to ConfigValue.IntValue(maxTokens), ConfigKey.TOPK to ConfigValue.IntValue(topK), ConfigKey.TOPP to ConfigValue.FloatValue(topP), ConfigKey.TEMPERATURE to ConfigValue.FloatValue(temperature), ConfigKey.ACCELERATOR to ConfigValue.StringValue(Accelerator.GPU.label), )
return Model( name = name, version = version, downloadFileName = modelFile, url = downloadUrl, sizeInBytes = sizeInBytes, info = description, configs = configs, llmSupportImage = llmSupportImage, configValues = configValues, ) } }
@Serializable data class ModelAllowlist(val models: List<AllowedModel>)
fun parseModelAllowlist(json: String): ModelAllowlist { val jsonParser = Json { ignoreUnknownKeys = true } return jsonParser.decodeFromString(json) }
/** * Populate task model lists from the allowlist. * Called once at app startup. */ fun populateTasksFromAllowlist(allowlist: ModelAllowlist) { MODELS_ASK_IMAGE.clear() MODELS_LLM_CHAT.clear()
for (allowed in allowlist.models) { val model = allowed.toModel() if (allowed.taskTypes.contains(TaskType.LLM_ASK_IMAGE.id)) { MODELS_ASK_IMAGE.add(model) } if (allowed.taskTypes.contains(TaskType.LLM_CHAT.id)) { MODELS_LLM_CHAT.add(model) } } }package com.qwen.vision.data
