/** A task listed on the home screen. */ data class Task( val type: TaskType, val icon: ImageVector? = null, val iconVectorResourceId: Int? = null, val models: MutableList<Model>, val description: String, val docUrl: String = "", val agentName: String = "Qwen", val textInputPlaceHolder: String = "Ask something...", var index: Int = -1, val updateTrigger: MutableState<Long> = mutableLongStateOf(0), )
