import android.graphics.Bitmap import java.util.UUID
enum class ChatMessageType { TEXT, IMAGE, LOADING, WARNING, INFO, }
enum class ChatSide { USER, AGENT }
sealed class ChatMessage( val id: String = UUID.randomUUID().toString(), open val type: ChatMessageType, open val side: ChatSide, open val latencyMs: Float = -1f, )
data class ChatMessageText( val content: String, override val side: ChatSide, val accelerator: String = "", override var latencyMs: Float = -1f, ) : ChatMessage(type = ChatMessageType.TEXT, side = side, latencyMs = latencyMs)
data class ChatMessageImage( val bitmap: Bitmap, override val side: ChatSide = ChatSide.USER, ) : ChatMessage(type = ChatMessageType.IMAGE, side = side)
data class ChatMessageLoading( val accelerator: String = "", override val side: ChatSide = ChatSide.AGENT, ) : ChatMessage(type = ChatMessageType.LOADING, side = side)
data class ChatMessageWarning( val message: String, override val side: ChatSide = ChatSide.AGENT, ) : ChatMessage(type = ChatMessageType.WARNING, side = side)
data class ChatMessageInfo( val message: String, override val side: ChatSide = ChatSide.AGENT, ) : ChatMessage(type = ChatMessageType.INFO, side = side)package com.qwen.vision.ui.common.chat
import androidx.lifecycle.ViewModel import com.qwen.vision.data.Model import com.qwen.vision.data.Task import kotlinx.coroutines.flow.MutableStateFlow import kotlinx.coroutines.flow.asStateFlow import kotlinx.coroutines.flow.update
data class ChatUiState( val inProgress: Boolean = false, val isResettingSession: Boolean = false, val preparing: Boolean = false, val messagesByModel: Map<String, MutableList<ChatMessage>> = mapOf(), val streamingMessagesByModel: Map<String, ChatMessage> = mapOf(), val timeToFirstToken: Long = 0L, val tokensPerSecond: Float = 0f, val totalGeneratedTokens: Int = 0, )
open class ChatViewModel(val task: Task) : ViewModel() { private val _uiState = MutableStateFlow(createInitialState(task)) val uiState = _uiState.asStateFlow()
private fun createInitialState(task: Task): ChatUiState { val messages = task.models.associate { model -> model.name to mutableListOf<ChatMessage>() } return ChatUiState(messagesByModel = messages) }
fun addMessage(model: Model, message: ChatMessage) { val newMap = _uiState.value.messagesByModel.toMutableMap() val list = newMap[model.name]?.toMutableList() ?: mutableListOf() list.add(message) newMap[model.name] = list _uiState.update { it.copy(messagesByModel = newMap) } }
fun removeLastMessage(model: Model) { val newMap = _uiState.value.messagesByModel.toMutableMap() val list = newMap[model.name]?.toMutableList() ?: return if (list.isNotEmpty()) list.removeAt(list.size - 1) newMap[model.name] = list _uiState.update { it.copy(messagesByModel = newMap) } }
fun getLastMessage(model: Model): ChatMessage? { return _uiState.value.messagesByModel[model.name]?.lastOrNull() }
fun updateLastTextMessageContentIncrementally(model: Model, partialContent: String, latencyMs: Float = -1f) { val newMap = _uiState.value.messagesByModel.toMutableMap() val list = newMap[model.name]?.toMutableList() ?: return val last = list.lastOrNull() if (last is ChatMessageText) { val updated = last.copy(content = last.content + partialContent, latencyMs = if (latencyMs >= 0) latencyMs else last.latencyMs) list[list.size - 1] = updated newMap[model.name] = list _uiState.update { it.copy(messagesByModel = newMap) } } }
fun setInProgress(value: Boolean) { _uiState.update { it.copy(inProgress = value) } }
fun setPreparing(value: Boolean) { _uiState.update { it.copy(preparing = value) } }
fun setResettingSession(value: Boolean) { _uiState.update { it.copy(isResettingSession = value) } }
fun clearMessages(model: Model) { val newMap = _uiState.value.messagesByModel.toMutableMap() newMap[model.name] = mutableListOf() _uiState.update { it.copy(messagesByModel = newMap) } }
fun ensureModelInState(model: Model) { if (!_uiState.value.messagesByModel.containsKey(model.name)) { val newMap = _uiState.value.messagesByModel.toMutableMap() newMap[model.name] = mutableListOf() _uiState.update { it.copy(messagesByModel = newMap) } } } }package com.qwen.vision.ui.common
import android.content.Context import android.graphics.Bitmap import android.graphics.BitmapFactory import android.net.Uri import android.util.Log
private const val TAG = "ImageUtils"
object ImageUtils {
/** * Decodes a bitmap from a URI, downsampling it to fit within the specified dimensions. * This prevents OutOfMemoryErrors when loading high-resolution images. */ fun decodeSampledBitmapFromUri( context: Context, uri: Uri, reqWidth: Int, reqHeight: Int ): Bitmap? { return try { // First decode with inJustDecodeBounds=true to check dimensions val options = BitmapFactory.Options().apply { inJustDecodeBounds = true } context.contentResolver.openInputStream(uri)?.use { BitmapFactory.decodeStream(it, null, options) }
// Calculate inSampleSize options.inSampleSize = calculateInSampleSize(options, reqWidth, reqHeight)
// Decode bitmap with inSampleSize set options.inJustDecodeBounds = false context.contentResolver.openInputStream(uri)?.use { BitmapFactory.decodeStream(it, null, options) } } catch (e: Exception) { Log.e(TAG, "Failed to decode bitmap from URI: ${e.message}") null } }
private fun calculateInSampleSize(options: BitmapFactory.Options, reqWidth: Int, reqHeight: Int): Int { // Raw height and width of image val (height: Int, width: Int) = options.run { outHeight to outWidth } var inSampleSize = 1
if (height > reqHeight || width > reqWidth) { val halfHeight: Int = height / 2 val halfWidth: Int = width / 2
// Calculate the largest inSampleSize value that is a power of 2 and keeps both // height and width larger than the requested height and width. while (halfHeight / inSampleSize >= reqHeight && halfWidth / inSampleSize >= reqWidth) { inSampleSize *= 2 } }
return inSampleSize } }package com.qwen.vision.ui.home
