private const val TAG = "ModelManagerViewModel"
enum class ModelInitStatus { NOT_INITIALIZED, INITIALIZING, INITIALIZED, ERROR, }
data class ModelState( val downloadState: DownloadState = DownloadState(), val initStatus: ModelInitStatus = ModelInitStatus.NOT_INITIALIZED, val initError: String = "", )
data class ModelManagerUiState( val modelStates: Map<String, ModelState> = emptyMap(), )
@HiltViewModel class ModelManagerViewModel @Inject constructor( private val downloadRepository: DownloadRepository, ) : ViewModel() {
private val _uiState = MutableStateFlow(ModelManagerUiState()) val uiState: StateFlow<ModelManagerUiState> = _uiState.asStateFlow()
init { // Start observing all models in the allowlist viewModelScope.launch { ALL_TASKS.flatMap { it.models }.distinctBy { it.name }.forEach { model -> launch { downloadRepository.observeWorkInfo(model).collect { downloadState -> updateModelState(model.name) { it.copy(downloadState = downloadState) } } } } } }
fun refreshDownloadStates(context: Context) { // Handled by init observers and explicit refresh of initial status val states = ALL_TASKS.flatMap { it.models }.associate { model -> model.name to (uiState.value.modelStates[model.name] ?: ModelState(downloadState = downloadRepository.getDownloadState(model))) } _uiState.update { it.copy(modelStates = states) } }
fun downloadModel(context: Context, model: Model) { downloadRepository.downloadModel(model) }
fun deleteModel(context: Context, model: Model) { viewModelScope.launch(Dispatchers.IO) { QwenModelHelper.cleanup(model) downloadRepository.deleteModel(model) updateModelState(model.name) { it.copy( downloadState = DownloadState(status = DownloadStatus.NOT_DOWNLOADED), initStatus = ModelInitStatus.NOT_INITIALIZED, initError = "", ) } } }
fun initializeModel(context: Context, model: Model) { if (getModelState(model.name).initStatus == ModelInitStatus.INITIALIZING) return if (getModelState(model.name).initStatus == ModelInitStatus.INITIALIZED) return
updateModelState(model.name) { it.copy(initStatus = ModelInitStatus.INITIALIZING, initError = "") }
viewModelScope.launch(Dispatchers.Default) { QwenModelHelper.initialize(context, model) { errorMsg -> if (errorMsg.isEmpty()) { updateModelState(model.name) { it.copy(initStatus = ModelInitStatus.INITIALIZED) } Log.d(TAG, "Model '${model.name}' ready") } else { updateModelState(model.name) { it.copy(initStatus = ModelInitStatus.ERROR, initError = errorMsg) } Log.e(TAG, "Model '${model.name}' init failed: $errorMsg") } } } }
fun getModelState(modelName: String): ModelState { return _uiState.value.modelStates[modelName] ?: ModelState() }
private fun updateModelState(modelName: String, update: (ModelState) -> ModelState) { _uiState.update { state -> val newStates = state.modelStates.toMutableMap() newStates[modelName] = update(newStates[modelName] ?: ModelState()) state.copy(modelStates = newStates) } } }package com.qwen.vision.ui.navigation
