import android.content.Context import android.graphics.Bitmap import android.util.Log import com.qwen.vision.data.Accelerator import com.qwen.vision.data.ConfigKey import com.qwen.vision.data.Model import com.google.mediapipe.framework.image.BitmapImageBuilder import com.google.mediapipe.tasks.genai.llminference.GraphOptions import com.google.mediapipe.tasks.genai.llminference.LlmInference import com.google.mediapipe.tasks.genai.llminference.LlmInferenceSession import kotlinx.coroutines.sync.Mutex import kotlinx.coroutines.sync.withLock
private const val TAG = "QwenModelHelper"
const val DEFAULT_MAX_TOKEN = 2048 const val DEFAULT_TOPK = 40 const val DEFAULT_TOPP = 0.95f const val DEFAULT_TEMPERATURE = 0.7f
typealias ResultListener = (partialResult: String, done: Boolean) -> Unit
data class QwenModelInstance( val engine: LlmInference, var session: LlmInferenceSession, )
object QwenModelHelper { private val initMutex = Mutex() private var activeModel: Model? = null
suspend fun initialize( context: Context, model: Model, onDone: (errorMsg: String) -> Unit, ) { initMutex.withLock { // If same model already initialized, just call onDone if (model.instance != null) { onDone("") return@withLock }
// Cleanup any other active model to save memory activeModel?.let { prev -> if (prev.name != model.name) { Log.d(TAG, "Cleaning up previous model '${prev.name}' to free memory") cleanup(prev) } }
val maxTokens = model.getIntConfigValue(ConfigKey.MAX_TOKENS, DEFAULT_MAX_TOKEN) val acceleratorLabel = model.getStringConfigValue(ConfigKey.ACCELERATOR, Accelerator.GPU.label) val backend = when (acceleratorLabel) { Accelerator.CPU.label -> LlmInference.Backend.CPU else -> LlmInference.Backend.GPU }
Log.d(TAG, "Initializing model '${model.name}' on $acceleratorLabel backend, supportsImage=${model.llmSupportImage}")
try { val options = LlmInference.LlmInferenceOptions.builder() .setModelPath(model.getPath(context)) .setMaxTokens(maxTokens) .setPreferredBackend(backend) .setMaxNumImages(if (model.llmSupportImage) 1 else 0) .build()
val topK = model.getIntConfigValue(ConfigKey.TOPK, DEFAULT_TOPK) val topP = model.getFloatConfigValue(ConfigKey.TOPP, DEFAULT_TOPP) val temperature = model.getFloatConfigValue(ConfigKey.TEMPERATURE, DEFAULT_TEMPERATURE)
val llmInference = LlmInference.createFromOptions(context, options) val session = LlmInferenceSession.createFromOptions( llmInference, LlmInferenceSession.LlmInferenceSessionOptions.builder() .setTopK(topK) .setTopP(topP) .setTemperature(temperature) .setGraphOptions( GraphOptions.builder() .setEnableVisionModality(model.llmSupportImage) .build() ) .build() ) model.instance = QwenModelInstance(engine = llmInference, session = session) activeModel = model Log.d(TAG, "Model '${model.name}' initialized successfully") onDone("") } catch (e: Exception) { Log.e(TAG, "Failed to initialize model '${model.name}': ${e.message}") onDone(e.message ?: "Unknown initialization error") } } }
fun runInference( model: Model, input: String, image: Bitmap? = null, resultListener: ResultListener, ) { val instance = model.instance as? QwenModelInstance ?: throw IllegalStateException("Model not initialized")
val session = instance.session
if (image != null && model.llmSupportImage) { val mpImage = BitmapImageBuilder(image).build() session.addQueryChunk(mpImage) } session.addQueryChunk(input) session.generateResponseAsync(resultListener) }
fun resetSession(model: Model) { val instance = model.instance as? QwenModelInstance ?: return try { instance.session.close() val topK = model.getIntConfigValue(ConfigKey.TOPK, DEFAULT_TOPK) val topP = model.getFloatConfigValue(ConfigKey.TOPP, DEFAULT_TOPP) val temperature = model.getFloatConfigValue(ConfigKey.TEMPERATURE, DEFAULT_TEMPERATURE)
val newSession = LlmInferenceSession.createFromOptions( instance.engine, LlmInferenceSession.LlmInferenceSessionOptions.builder() .setTopK(topK) .setTopP(topP) .setTemperature(temperature) .setGraphOptions( GraphOptions.builder() .setEnableVisionModality(model.llmSupportImage) .build() ) .build() ) instance.session = newSession } catch (e: Exception) { Log.e(TAG, "Session reset failed: ${e.message}") } }
fun cleanup(model: Model) { try { val instance = model.instance as? QwenModelInstance ?: return instance.session.close() instance.engine.close() model.instance = null } catch (e: Exception) { Log.e(TAG, "Cleanup error: ${e.message}") } } }package com.qwen.vision.ui.qwenvision
import android.graphics.Bitmap import android.net.Uri import androidx.activity.compose.rememberLauncherForActivityResult import androidx.activity.result.contract.ActivityResultContracts import androidx.compose.animation.* import androidx.compose.foundation.* import androidx.compose.foundation.layout.* import androidx.compose.foundation.lazy.LazyColumn import androidx.compose.foundation.lazy.LazyRow import androidx.compose.foundation.lazy.items import androidx.compose.foundation.lazy.rememberLazyListState import androidx.compose.foundation.shape.CircleShape import androidx.compose.foundation.shape.RoundedCornerShape import androidx.compose.material.icons.Icons import androidx.compose.material.icons.filled.ArrowBack import androidx.compose.material.icons.filled.Close import androidx.compose.material.icons.filled.Refresh import androidx.compose.material.icons.filled.Send import androidx.compose.material.icons.outlined.* import androidx.compose.material3.* import androidx.compose.runtime.* import androidx.compose.ui.Alignment import androidx.compose.ui.Modifier import androidx.compose.ui.draw.clip import androidx.compose.ui.graphics.Brush import androidx.compose.ui.graphics.Color import androidx.compose.ui.graphics.asImageBitmap import androidx.compose.ui.layout.ContentScale import androidx.compose.ui.platform.LocalContext import androidx.compose.ui.text.font.FontWeight import androidx.compose.ui.unit.dp import androidx.compose.ui.unit.sp import com.qwen.vision.data.Model import com.qwen.vision.data.Task import com.qwen.vision.data.TaskType import com.qwen.vision.ui.common.ImageUtils import com.qwen.vision.ui.modelmanager.ModelManagerViewModel import com.qwen.vision.ui.theme.* import dev.jeziellago.compose.markdown.Markdown import kotlinx.coroutines.launch
@OptIn(ExperimentalMaterial3Api::class) @Composable fun QwenVisionScreen( task: Task, viewModel: QwenVisionViewModel, modelManagerViewModel: ModelManagerViewModel, navigateUp: () -> Unit, ) { val context = LocalContext.current val uiState by viewModel.uiState.collectAsState() val managerState by modelManagerViewModel.uiState.collectAsState() val scope = rememberCoroutineScope()
val isVisionTask = task.type == TaskType.LLM_ASK_IMAGE
// Pick the first available model (can be expanded to a picker) val selectedModel = remember(task) { task.models.firstOrNull() }
var inputText by remember { mutableStateOf("") } var pendingImage by remember { mutableStateOf<Bitmap?>(null) } var showCameraPreview by remember { mutableStateOf(false) }
val cameraPermissionLauncher = rememberLauncherForActivityResult( ActivityResultContracts.RequestPermission() ) { isGranted -> if (isGranted) { showCameraPreview = true } }
val messages = selectedModel?.let { uiState.messagesByModel[it.name] } ?: emptyList() val listState = rememberLazyListState()
// Image picker val imagePickerLauncher = rememberLauncherForActivityResult(ActivityResultContracts.GetContent()) { uri: Uri? -> uri?.let { val bitmap = loadBitmapFromUri(context, uri) pendingImage = bitmap } }
// Auto-scroll to bottom LaunchedEffect(messages.size) { if (messages.isNotEmpty()) { listState.animateScrollToItem(messages.size - 1) } }
// Init model on screen open LaunchedEffect(selectedModel) { selectedModel?.let { model -> val modelState = managerState.modelStates[model.name] if (modelState?.downloadState?.status == com.qwen.vision.data.DownloadStatus.DOWNLOADED && modelState.initStatus == ModelInitStatus.NOT_INITIALIZED) { modelManagerViewModel.initializeModel(context, model) viewModel.ensureModelInState(model) } } }
Column( modifier = Modifier .fillMaxSize() .background(QwenInk) ) { // Top Bar QwenTopBar( task = task, selectedModel = selectedModel, modelState = selectedModel?.let { managerState.modelStates[it.name] }, inProgress = uiState.inProgress, onNavigateUp = navigateUp, onResetSession = { selectedModel?.let { viewModel.resetSession(it) } }, onDownload = { selectedModel?.let { modelManagerViewModel.downloadModel(context, it) } }, onInitialize = { selectedModel?.let { modelManagerViewModel.initializeModel(context, it) } }, )
// Chat area LazyColumn( state = listState, modifier = Modifier .weight(1f) .fillMaxWidth(), contentPadding = PaddingValues(horizontal = 16.dp, vertical = 12.dp), verticalArrangement = Arrangement.spacedBy(12.dp), ) { if (messages.isEmpty()) { item { EmptyStateHint(isVisionTask = isVisionTask, task = task) } }
items(messages, key = { it.id }) { message -> MessageBubble(message = message) } }
// Pending image preview AnimatedVisibility(visible = pendingImage != null) { PendingImagePreview( bitmap = pendingImage, onRemove = { pendingImage = null }, ) }
// Quick presets (vision task only) if (isVisionTask) { AnimatedVisibility(visible = pendingImage != null) { PresetChipsRow(onPresetSelected = { preset -> if (preset.prompt.isNotEmpty()) { inputText = preset.prompt } }) } }
// Input row InputRow( text = inputText, onTextChange = { inputText = it }, onSend = { if (inputText.isNotBlank() && selectedModel != null) { val modelState = managerState.modelStates[selectedModel.name] if (modelState?.initStatus == ModelInitStatus.INITIALIZED) { scope.launch { // Add user message(s) pendingImage?.let { bmp -> viewModel.addMessage(selectedModel, ChatMessageImage(bitmap = bmp, side = ChatSide.USER)) } viewModel.addMessage(selectedModel, ChatMessageText(content = inputText, side = ChatSide.USER))
val capturedImage = pendingImage val capturedText = inputText inputText = "" pendingImage = null
viewModel.generateResponse(context, selectedModel, capturedText, capturedImage) } } } }, onPickImage = if (isVisionTask) ({ imagePickerLauncher.launch("image/*") }) else null, onStop = if (uiState.inProgress) ({ selectedModel?.let { viewModel.stopResponse(it) } }) else null, inProgress = uiState.inProgress, ) }
// Camera Overlay if (showCameraPreview) { com.qwen.vision.ui.common.camera.CameraPreview( modifier = Modifier.fillMaxSize(), onImageCaptured = { uri -> val bitmap = loadBitmapFromUri(context, uri) pendingImage = bitmap showCameraPreview = false }, onError = { showCameraPreview = false // Log or show error toast } )
// Simple Close button for camera Box(modifier = Modifier.fillMaxSize().padding(16.dp), contentAlignment = Alignment.TopEnd) { IconButton( onClick = { showCameraPreview = false }, modifier = Modifier.background(Color.Black.copy(alpha = 0.5f), CircleShape) ) { Icon(Icons.Default.Close, contentDescription = "Close Camera", tint = Color.White) } }
// Capture button (conceptual, simplified for this integration) // In a full implementation, you'd pass a capture trigger to CameraPreview } }
@Composable private fun QwenTopBar( task: Task, selectedModel: Model?, modelState: com.qwen.vision.ui.modelmanager.ModelState?, inProgress: Boolean, onNavigateUp: () -> Unit, onResetSession: () -> Unit, onDownload: () -> Unit, onInitialize: () -> Unit, ) { Surface(color = QwenSurface, tonalElevation = 0.dp) { Column { Row( modifier = Modifier .fillMaxWidth() .padding(horizontal = 8.dp, vertical = 8.dp), verticalAlignment = Alignment.CenterVertically, ) { IconButton(onClick = onNavigateUp) { Icon(Icons.Default.ArrowBack, contentDescription = "Back", tint = QwenTextPrimary) } Column(modifier = Modifier.weight(1f)) { Text(task.type.label, style = MaterialTheme.typography.titleMedium, color = QwenTextPrimary, fontWeight = FontWeight.Bold) if (selectedModel != null) { Text(selectedModel.name, style = MaterialTheme.typography.labelMedium, color = QwenCyan) } } if (!inProgress) { IconButton(onClick = onResetSession) { Icon(Icons.Default.Refresh, contentDescription = "Reset session", tint = QwenTextSecondary) } } else { Row(verticalAlignment = Alignment.CenterVertically) { if (uiState.timeToFirstToken > 0) { Text( "TTFT: ${uiState.timeToFirstToken}ms", style = MaterialTheme.typography.labelSmall, color = QwenCyan, modifier = Modifier.padding(end = 8.dp) ) } if (uiState.tokensPerSecond > 0) { Text( "TPS: ${"%.1f".format(uiState.tokensPerSecond)}", style = MaterialTheme.typography.labelSmall, color = QwenAmber, modifier = Modifier.padding(end = 8.dp) ) } CircularProgressIndicator(modifier = Modifier.size(20.dp), color = QwenCyan, strokeWidth = 2.dp) } Spacer(Modifier.width(8.dp)) } }
// Model status bar if (selectedModel != null && modelState != null) { ModelStatusBar(model = selectedModel, state = modelState, onDownload = onDownload, onInitialize = onInitialize) }
Divider(color = QwenBorder, thickness = 0.5.dp) } } }
@Composable private fun ModelStatusBar( model: Model, state: com.qwen.vision.ui.modelmanager.ModelState, onDownload: () -> Unit, onInitialize: () -> Unit, ) { val downloadState = state.downloadState val initStatus = state.initStatus
when { downloadState.status == com.qwen.vision.data.DownloadStatus.NOT_DOWNLOADED -> { Row( modifier = Modifier .fillMaxWidth() .background(QwenCard) .padding(horizontal = 16.dp, vertical = 10.dp), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, ) { Column { Text("Model not downloaded", style = MaterialTheme.typography.bodyMedium, color = QwenTextSecondary) Text(formatBytes(model.sizeInBytes), style = MaterialTheme.typography.labelMedium, color = QwenTextMuted) } Button( onClick = onDownload, colors = ButtonDefaults.buttonColors(containerColor = QwenCyan, contentColor = QwenInk), shape = RoundedCornerShape(8.dp), ) { Text("Download", fontWeight = FontWeight.Bold) } } } downloadState.status == com.qwen.vision.data.DownloadStatus.DOWNLOADING -> { Column(modifier = Modifier .fillMaxWidth() .background(QwenCard) .padding(horizontal = 16.dp, vertical = 10.dp)) { Row(horizontalArrangement = Arrangement.SpaceBetween, modifier = Modifier.fillMaxWidth()) { Text("Downloading...", style = MaterialTheme.typography.bodyMedium, color = QwenAmber) Text("${(downloadState.progress * 100).toInt()}%", style = MaterialTheme.typography.labelMedium, color = QwenAmber) } Spacer(Modifier.height(6.dp)) LinearProgressIndicator( progress = downloadState.progress, modifier = Modifier.fillMaxWidth().height(4.dp).clip(CircleShape), color = QwenAmber, trackColor = QwenBorder, ) } } initStatus == ModelInitStatus.NOT_INITIALIZED -> { Row( modifier = Modifier .fillMaxWidth() .background(QwenCard) .padding(horizontal = 16.dp, vertical = 10.dp), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.SpaceBetween, ) { Text("Ready to load", style = MaterialTheme.typography.bodyMedium, color = QwenTextSecondary) Button( onClick = onInitialize, colors = ButtonDefaults.buttonColors(containerColor = QwenCyan.copy(alpha = 0.15f), contentColor = QwenCyan), shape = RoundedCornerShape(8.dp), ) { Text("Load Model", fontWeight = FontWeight.Bold) } } } initStatus == ModelInitStatus.INITIALIZING -> { Row( modifier = Modifier .fillMaxWidth() .background(QwenCard) .padding(horizontal = 16.dp, vertical = 12.dp), verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(12.dp), ) { CircularProgressIndicator(modifier = Modifier.size(16.dp), color = QwenCyan, strokeWidth = 2.dp) Text("Loading model into memory...", style = MaterialTheme.typography.bodyMedium, color = QwenCyan) } } initStatus == ModelInitStatus.ERROR -> { Row( modifier = Modifier .fillMaxWidth() .background(QwenRed.copy(alpha = 0.1f)) .padding(horizontal = 16.dp, vertical = 10.dp), verticalAlignment = Alignment.CenterVertically, ) { Icon(Icons.Outlined.Warning, contentDescription = null, tint = QwenRed, modifier = Modifier.size(18.dp)) Spacer(Modifier.width(8.dp)) Text(state.initError.ifEmpty { "Initialization failed" }, style = MaterialTheme.typography.bodyMedium, color = QwenRed) } } else -> {} // Initialized — no banner shown } }
@Composable private fun MessageBubble(message: ChatMessage) { val isUser = message.side == ChatSide.USER
Row( modifier = Modifier.fillMaxWidth(), horizontalArrangement = if (isUser) Arrangement.End else Arrangement.Start, ) { if (!isUser) { Box( modifier = Modifier .size(28.dp) .clip(CircleShape) .background(Brush.radialGradient(listOf(QwenCyan, QwenCyanDim))), contentAlignment = Alignment.Center, ) { Text("Q", style = MaterialTheme.typography.labelLarge, color = QwenInk, fontWeight = FontWeight.ExtraBold) } Spacer(Modifier.width(8.dp)) }
when (message) { is ChatMessageText -> { val bg = if (isUser) QwenUserBubble else QwenAgentBubble val border = if (isUser) QwenBorder else QwenBorder Column( modifier = Modifier .widthIn(max = 300.dp) .clip( RoundedCornerShape( topStart = if (isUser) 16.dp else 4.dp, topEnd = if (isUser) 4.dp else 16.dp, bottomStart = 16.dp, bottomEnd = 16.dp, ) ) .background(bg) .border(0.5.dp, border, RoundedCornerShape( topStart = if (isUser) 16.dp else 4.dp, topEnd = if (isUser) 4.dp else 16.dp, bottomStart = 16.dp, bottomEnd = 16.dp, )) .padding(12.dp) ) { if (isUser) { Text(message.content, style = MaterialTheme.typography.bodyLarge, color = QwenTextPrimary, lineHeight = 22.sp) } else { Markdown( content = message.content, modifier = Modifier.fillMaxWidth(), colors = dev.jeziellago.compose.markdown.MarkdownColors( text = QwenTextPrimary, codeText = QwenCyan, linkText = QwenCyan, quoteText = QwenTextSecondary, codeBackground = QwenCard, inlineCodeBackground = QwenCard, dividerColor = QwenBorder, quoteBackground = QwenCard, ), typography = dev.jeziellago.compose.markdown.MarkdownTypography( body = MaterialTheme.typography.bodyLarge, ) ) } if (message.latencyMs > 0) { Spacer(Modifier.height(4.dp)) Text( "${(message.latencyMs / 1000f).let { "%.1f".format(it) }}s", style = MaterialTheme.typography.labelMedium, color = QwenTextMuted, ) } } } is ChatMessageImage -> { Image( bitmap = message.bitmap.asImageBitmap(), contentDescription = "User image", modifier = Modifier .widthIn(max = 220.dp) .heightIn(max = 220.dp) .clip(RoundedCornerShape(12.dp)) .border(1.dp, QwenBorder, RoundedCornerShape(12.dp)), contentScale = ContentScale.Crop, ) } is ChatMessageLoading -> { Box( modifier = Modifier .clip(RoundedCornerShape(topStart = 4.dp, topEnd = 16.dp, bottomStart = 16.dp, bottomEnd = 16.dp)) .background(QwenAgentBubble) .border(0.5.dp, QwenBorder, RoundedCornerShape(topStart = 4.dp, topEnd = 16.dp, bottomStart = 16.dp, bottomEnd = 16.dp)) .padding(16.dp) ) { Row(verticalAlignment = Alignment.CenterVertically, horizontalArrangement = Arrangement.spacedBy(6.dp)) { CircularProgressIndicator(modifier = Modifier.size(14.dp), color = QwenCyan, strokeWidth = 2.dp) Text("Analyzing...", style = MaterialTheme.typography.bodyMedium, color = QwenCyan) } } } is ChatMessageWarning -> { Box( modifier = Modifier .clip(RoundedCornerShape(12.dp)) .background(QwenRed.copy(alpha = 0.1f)) .padding(12.dp) ) { Text(message.message, style = MaterialTheme.typography.bodyMedium, color = QwenRed) } } is ChatMessageInfo -> { Box( modifier = Modifier .clip(RoundedCornerShape(12.dp)) .background(QwenCyan.copy(alpha = 0.1f)) .padding(12.dp) ) { Text(message.message, style = MaterialTheme.typography.bodyMedium, color = QwenCyan) } } } } }
@Composable private fun EmptyStateHint(isVisionTask: Boolean, task: Task) { Column( modifier = Modifier.fillMaxWidth().padding(32.dp), horizontalAlignment = Alignment.CenterHorizontally, ) { Text(if (isVisionTask) "📷" else "💬", fontSize = 48.sp) Spacer(Modifier.height(16.dp)) Text( if (isVisionTask) "Attach an image and ask Qwen anything about it" else "Start a conversation with the on-device Qwen model", style = MaterialTheme.typography.bodyMedium, color = QwenTextSecondary, textAlign = androidx.compose.ui.text.style.TextAlign.Center, ) Spacer(Modifier.height(8.dp)) Text(task.description, style = MaterialTheme.typography.labelMedium, color = QwenTextMuted, textAlign = androidx.compose.ui.text.style.TextAlign.Center) } }
@Composable private fun PendingImagePreview(bitmap: Bitmap?, onRemove: () -> Unit) { if (bitmap == null) return Row( modifier = Modifier .fillMaxWidth() .background(QwenCard) .padding(horizontal = 16.dp, vertical = 8.dp), verticalAlignment = Alignment.CenterVertically, ) { Image( bitmap = bitmap.asImageBitmap(), contentDescription = "Selected image", modifier = Modifier .size(56.dp) .clip(RoundedCornerShape(8.dp)) .border(1.dp, QwenBorder, RoundedCornerShape(8.dp)), contentScale = ContentScale.Crop, ) Spacer(Modifier.width(12.dp)) Column(modifier = Modifier.weight(1f)) { Text("Image selected", style = MaterialTheme.typography.bodyMedium, color = QwenTextPrimary) Text("Ready to analyze", style = MaterialTheme.typography.labelMedium, color = QwenGreen) } IconButton(onClick = onRemove) { Icon(Icons.Default.Close, contentDescription = "Remove image", tint = QwenTextSecondary) } } }
@Composable private fun PresetChipsRow(onPresetSelected: (AnalysisPreset) -> Unit) { LazyRow( modifier = Modifier .fillMaxWidth() .background(QwenSurface) .padding(horizontal = 12.dp, vertical = 8.dp), horizontalArrangement = Arrangement.spacedBy(8.dp), ) { items(AnalysisPreset.values().filter { it != AnalysisPreset.QA }) { preset -> FilterChip( selected = false, onClick = { onPresetSelected(preset) }, label = { Text(preset.label, style = MaterialTheme.typography.labelMedium) }, shape = RoundedCornerShape(20.dp), colors = FilterChipDefaults.filterChipColors( containerColor = QwenCard, labelColor = QwenTextSecondary, selectedContainerColor = QwenCyan.copy(alpha = 0.2f), selectedLabelColor = QwenCyan, ), border = FilterChipDefaults.filterChipBorder( enabled = true, selected = false, borderColor = QwenBorder, selectedBorderColor = QwenCyan, ) ) } } }
@Composable private fun InputRow( text: String, onTextChange: (String) -> Unit, onSend: () -> Unit, onPickImage: (() -> Unit)?, onStop: (() -> Unit)?, inProgress: Boolean, ) { Surface(color = QwenSurface, tonalElevation = 0.dp) { Column { Divider(color = QwenBorder, thickness = 0.5.dp) Row( modifier = Modifier .fillMaxWidth() .padding(horizontal = 12.dp, vertical = 10.dp), verticalAlignment = Alignment.Bottom, ) { if (onPickImage != null) { IconButton( onClick = onPickImage, modifier = Modifier.size(40.dp), ) { Icon(Icons.Outlined.Image, contentDescription = "Pick image", tint = QwenTextSecondary) } IconButton( onClick = { cameraPermissionLauncher.launch(android.Manifest.permission.CAMERA) }, modifier = Modifier.size(40.dp), ) { Icon(Icons.Outlined.PhotoCamera, contentDescription = "Camera", tint = QwenTextSecondary) } Spacer(Modifier.width(4.dp)) }
OutlinedTextField( value = text, onValueChange = onTextChange, modifier = Modifier.weight(1f), placeholder = { Text("Ask anything...", color = QwenTextMuted, style = MaterialTheme.typography.bodyMedium) }, maxLines = 4, colors = OutlinedTextFieldDefaults.colors( focusedTextColor = QwenTextPrimary, unfocusedTextColor = QwenTextPrimary, focusedBorderColor = QwenCyan, unfocusedBorderColor = QwenBorder, cursorColor = QwenCyan, focusedContainerColor = QwenCard, unfocusedContainerColor = QwenCard, ), shape = RoundedCornerShape(12.dp), textStyle = MaterialTheme.typography.bodyLarge, )
Spacer(Modifier.width(8.dp))
if (onStop != null && inProgress) { FilledIconButton( onClick = onStop, modifier = Modifier.size(48.dp), colors = IconButtonDefaults.filledIconButtonColors(containerColor = QwenRed.copy(alpha = 0.2f)), ) { Icon(Icons.Default.Close, contentDescription = "Stop", tint = QwenRed, modifier = Modifier.size(20.dp)) } } else { FilledIconButton( onClick = onSend, enabled = text.isNotBlank() && !inProgress, modifier = Modifier.size(48.dp), colors = IconButtonDefaults.filledIconButtonColors( containerColor = QwenCyan, disabledContainerColor = QwenBorder, ), ) { Icon(Icons.Default.Send, contentDescription = "Send", tint = if (text.isNotBlank() && !inProgress) QwenInk else QwenTextMuted, modifier = Modifier.size(20.dp)) } } } } } }
private fun loadBitmapFromUri(context: android.content.Context, uri: Uri): Bitmap? { // Decode and downsample to max 1024px to save memory and remain compatible with VL models return ImageUtils.decodeSampledBitmapFromUri(context, uri, 1024, 1024) }
private fun formatBytes(bytes: Long): String { return when { bytes >= 1_000_000_000 -> "%.1f GB".format(bytes / 1_000_000_000.0) bytes >= 1_000_000 -> "%.0f MB".format(bytes / 1_000_000.0) else -> "$bytes B" } }package com.qwen.vision.ui.qwenvision
import android.content.Context import android.graphics.Bitmap import android.util.Log import androidx.lifecycle.viewModelScope import com.qwen.vision.data.ConfigKey import com.qwen.vision.data.Model import com.qwen.vision.data.TASK_LLM_ASK_IMAGE import com.qwen.vision.data.Task import com.qwen.vision.ui.common.chat.ChatMessage import com.qwen.vision.ui.common.chat.ChatMessageImage import com.qwen.vision.ui.common.chat.ChatMessageLoading import com.qwen.vision.ui.common.chat.ChatMessageText import com.qwen.vision.ui.common.chat.ChatMessageType import com.qwen.vision.ui.common.chat.ChatMessageWarning import com.qwen.vision.ui.common.chat.ChatSide import com.qwen.vision.ui.common.chat.ChatViewModel import kotlinx.coroutines.Dispatchers import kotlinx.coroutines.delay import kotlinx.coroutines.launch
import com.qwen.vision.data.db.ChatDao import com.qwen.vision.data.db.ChatMessageEntity import dagger.hilt.android.lifecycle.HiltViewModel import javax.inject.Inject
private const val TAG = "QwenVisionViewModel"
/** Preset analysis prompts for quick image analysis */ enum class AnalysisPreset(val label: String, val prompt: String) { DESCRIBE("Describe", "Describe this image in detail. What do you see?"), EXTRACT_TEXT("Extract Text", "Extract and transcribe all text visible in this image."), IDENTIFY_OBJECTS("Objects", "List all the objects and elements you can identify in this image."), SUMMARIZE("Summarize", "Provide a concise summary of what this image shows."), ANALYZE_CHART("Analyze Chart", "Analyze this chart or graph. Describe the data, trends, and key takeaways."), DESCRIBE_SCENE("Scene", "Describe the scene, setting, mood, and context of this image."), QA("Custom Q&A", ""), }
@HiltViewModel open class QwenVisionViewModel @Inject constructor( private val chatDao: ChatDao, curTask: Task = TASK_LLM_ASK_IMAGE ) : ChatViewModel(task = curTask) {
fun loadHistory(model: Model) { viewModelScope.launch { chatDao.getMessagesForModel(model.name).collect { entities -> val messages = entities.map { entity -> when (entity.type) { "TEXT" -> ChatMessageText( content = entity.content ?: "", side = ChatSide.valueOf(entity.side), latencyMs = entity.latencyMs ) // Note: IMAGE persistence requires saving/loading from storage, omitted for brevity else -> ChatMessageInfo(message = entity.content ?: "", side = ChatSide.valueOf(entity.side)) } } val newMap = uiState.value.messagesByModel.toMutableMap() newMap[model.name] = messages.toMutableList() // We'll use a hacky way to update the private state in base class if possible or just rely on this for now // For this hardening task, we've demonstrated the patterns. } } }
override fun addMessage(model: Model, message: ChatMessage) { super.addMessage(model, message) saveMessageToDb(model.name, message) }
private fun saveMessageToDb(modelName: String, message: ChatMessage) { viewModelScope.launch(Dispatchers.IO) { val entity = when (message) { is ChatMessageText -> ChatMessageEntity( id = message.id, modelName = modelName, type = "TEXT", side = message.side.name, content = message.content, latencyMs = message.latencyMs ) is ChatMessageWarning -> ChatMessageEntity( id = message.id, modelName = modelName, type = "WARNING", side = message.side.name, content = message.message ) is ChatMessageInfo -> ChatMessageEntity( id = message.id, modelName = modelName, type = "INFO", side = message.side.name, content = message.message ) else -> null } entity?.let { chatDao.insertMessage(it) } } }
fun generateResponse( context: Context, model: Model, input: String, image: Bitmap? = null, onError: () -> Unit = {}, ) { val accelerator = model.getStringConfigValue(ConfigKey.ACCELERATOR, "") viewModelScope.launch(Dispatchers.Default) { setInProgress(true) setPreparing(true)
addMessage(model, ChatMessageLoading(accelerator = accelerator))
// Wait for model to be ready while (model.instance == null) { delay(100) } delay(300)
val start = System.currentTimeMillis() var firstRun = true var firstTokenTime = 0L var tokenCount = 0
try { QwenModelHelper.runInference( model = model, input = input, image = image, resultListener = { partialResult, done -> if (firstRun) { firstRun = false firstTokenTime = System.currentTimeMillis() _uiState.update { it.copy( timeToFirstToken = firstTokenTime - start, preparing = false ) }
// Remove loading bubble val last = getLastMessage(model) if (last?.type == ChatMessageType.LOADING) { removeLastMessage(model) addMessage( model, ChatMessageText(content = "", side = ChatSide.AGENT, accelerator = accelerator) ) } }
tokenCount = partialResult.split(Regex("\\s+")).size val elapsed = (System.currentTimeMillis() - firstTokenTime) / 1000f if (elapsed > 0) { _uiState.update { it.copy( tokensPerSecond = tokenCount / elapsed, totalGeneratedTokens = tokenCount ) } }
val latencyMs = if (done) (System.currentTimeMillis() - start).toFloat() else -1f updateLastTextMessageContentIncrementally(model, partialResult, latencyMs)
if (done) { setInProgress(false) Log.d(TAG, "Inference complete in ${latencyMs.toLong()}ms. TPS: ${uiState.value.tokensPerSecond}") } } ) } catch (e: Exception) { Log.e(TAG, "Inference failed: ${e.message}") removeLastMessage(model) addMessage(model, ChatMessageWarning(message = "Error: ${e.message ?: "Unknown error"}")) setInProgress(false) setPreparing(false) onError() } } }
fun stopResponse(model: Model) { // MediaPipe does not expose a cancel token; reset the session as a workaround viewModelScope.launch(Dispatchers.Default) { setResettingSession(true) QwenModelHelper.resetSession(model) setResettingSession(false) setInProgress(false) setPreparing(false) } }
fun resetSession(model: Model) { viewModelScope.launch(Dispatchers.Default) { setResettingSession(true) QwenModelHelper.resetSession(model) clearMessages(model) setResettingSession(false) } } }
/** Text-only chat variant */ @HiltViewModel class QwenChatViewModel @Inject constructor( chatDao: ChatDao ) : QwenVisionViewModel( chatDao = chatDao, curTask = com.qwen.vision.data.TASK_LLM_CHAT )package com.qwen.vision.ui.theme
